import { NavLink } from 'react-bootstrap';
import Nav from 'react-bootstrap/Nav';
import "/Navigation.css";

function Navigation() {
  return (
    <Nav fill variant="tabs" defaultActiveKey="/home">
      <Nav.Item>
        <Nav.Link as={NavLink} href="/" eventKey="home" className="custom-tab">Home</Nav.Link>
        </Nav.Item>
        <Nav.Item>
        <Nav.Link as={NavLink} href="/resume" eventKey="resume" className="custom-tab">Resume</Nav.Link>
        </Nav.Item>
        <Nav.Item>
        <Nav.Link as={NavLink} href="/publications" eventKey="publications" className="custom-tab">Publications</Nav.Link>
        </Nav.Item>
        <Nav.Item>
        <Nav.Link as={NavLink} href="/contact" eventKey="contact" className="custom-tab">Contact</Nav.Link>
      </Nav.Item>

    </Nav>
  );
}

export default Navigation;
